/**
 * withAndroidWidget.js — Expo Config Plugin
 *
 * Injects the TibiaOT home-screen widget into the Android native project
 * generated by `expo prebuild`.  All source files live under mobile/plugins/
 * so they survive the `--clean` flag used in build-android.sh.
 *
 * What this plugin does:
 *  1. Copies TibiaWidgetProvider.java → android/app/src/main/java/…/widget/
 *  2. Copies XML resources            → android/app/src/main/res/{layout,xml,drawable}/
 *  3. Registers the AppWidgetProvider receiver in AndroidManifest.xml
 *
 * NO native module / NO MainApplication.kt patching required.
 * The widget reads backendUrl + sessionId directly from AsyncStorage's SQLite
 * database — AppContext.js writes the values there on every connect/disconnect.
 */

const { withAndroidManifest, withDangerousMod } = require('@expo/config-plugins');
const path = require('path');
const fs   = require('fs');

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function copyFile(src, dest) {
  fs.mkdirSync(path.dirname(dest), { recursive: true });
  fs.copyFileSync(src, dest);
}

// ---------------------------------------------------------------------------
// Step 1 – copy Java source + XML resources into the generated android/ dir
// ---------------------------------------------------------------------------

function withWidgetFiles(config) {
  return withDangerousMod(config, [
    'android',
    async (cfg) => {
      const androidRoot = cfg.modRequest.platformProjectRoot;
      const pluginsDir  = path.join(cfg.modRequest.projectRoot, 'plugins');

      // Widget provider Java source
      const javaDest = path.join(
        androidRoot,
        'app/src/main/java/com/tibiaotmonitor/widget',
      );
      copyFile(
        path.join(pluginsDir, 'java', 'TibiaWidgetProvider.java'),
        path.join(javaDest,           'TibiaWidgetProvider.java'),
      );

      // XML resources
      copyFile(
        path.join(pluginsDir, 'res/layout/tibia_widget_layout.xml'),
        path.join(androidRoot, 'app/src/main/res/layout/tibia_widget_layout.xml'),
      );
      copyFile(
        path.join(pluginsDir, 'res/xml/tibia_widget_info.xml'),
        path.join(androidRoot, 'app/src/main/res/xml/tibia_widget_info.xml'),
      );
      copyFile(
        path.join(pluginsDir, 'res/drawable/widget_bg.xml'),
        path.join(androidRoot, 'app/src/main/res/drawable/widget_bg.xml'),
      );

      return cfg;
    },
  ]);
}

// ---------------------------------------------------------------------------
// Step 2 – register the AppWidgetProvider receiver in AndroidManifest.xml
// ---------------------------------------------------------------------------

function withWidgetManifest(config) {
  return withAndroidManifest(config, (cfg) => {
    const application = cfg.modResults.manifest.application[0];

    if (!application.receiver) application.receiver = [];

    // Avoid duplicate entries on repeated prebuild runs
    const alreadyRegistered = application.receiver.some(
      (r) =>
        r.$['android:name'] === 'com.tibiaotmonitor.widget.TibiaWidgetProvider',
    );
    if (alreadyRegistered) return cfg;

    application.receiver.push({
      $: {
        'android:name':     'com.tibiaotmonitor.widget.TibiaWidgetProvider',
        'android:exported': 'true',
      },
      'intent-filter': [
        {
          action: [
            { $: { 'android:name': 'android.appwidget.action.APPWIDGET_UPDATE' } },
          ],
        },
      ],
      'meta-data': [
        {
          $: {
            'android:name':     'android.appwidget.provider',
            'android:resource': '@xml/tibia_widget_info',
          },
        },
      ],
    });

    return cfg;
  });
}

// ---------------------------------------------------------------------------
// Compose
// ---------------------------------------------------------------------------

const withAndroidWidget = (config) => {
  config = withWidgetFiles(config);
  config = withWidgetManifest(config);
  return config;
};

module.exports = withAndroidWidget;
